INSERT INTO quiz_questions (quiz_id, question_text, question_type, options, correct_answer, explanation)
VALUES
('3e92af45-a32b-4dc9-aeac-dcc6d36c64e4', 'Trong dạng bài True/False/Not Given của IELTS Reading, khi nào bạn nên chọn đáp án ''False''?', 'multiple_choice', '["Khi thông tin trong bài không đề cập đến từ khóa trong câu hỏi.","Khi thông tin trong bài viết hoàn toàn trái ngược hoặc phủ định lại nội dung của câu hỏi.","Khi bạn nghĩ rằng thông tin đó sai dựa trên kiến thức cá nhân của bạn.","Khi câu hỏi sử dụng các từ như ''always'' hoặc ''never''."]', 'Khi thông tin trong bài viết hoàn toàn trái ngược hoặc phủ định lại nội dung của câu hỏi.', '''False'' chỉ được chọn khi văn bản gốc có thông tin nói rõ điều ngược lại với nhận định trong câu hỏi. Nếu không tìm thấy thông tin để xác nhận đúng/sai, đáp án phải là ''Not Given''.'),
('3e92af45-a32b-4dc9-aeac-dcc6d36c64e4', 'Lỗi tư duy phổ biến nhất khiến thí sinh nhầm lẫn giữa ''False'' và ''Not Given'' là gì?', 'multiple_choice', '["Không biết dịch từ vựng.","Đọc quá chậm.","Tự suy diễn logic (Overthinking): tự mặc định rằng thông tin không được nhắc đến có nghĩa là nó sai.","Không gạch chân từ khóa."]', 'Tự suy diễn logic (Overthinking): tự mặc định rằng thông tin không được nhắc đến có nghĩa là nó sai.', 'Trong IELTS, bạn chỉ được dựa vào những gì tác giả viết. Nếu bài viết không cung cấp đủ dữ kiện để khẳng định câu đó sai, thì đáp án bắt buộc phải là ''Not Given''.'),
('3e92af45-a32b-4dc9-aeac-dcc6d36c64e4', 'Đối với dạng bài True/False/Not Given, trình tự xuất hiện của các câu hỏi thường như thế nào so với văn bản?', 'multiple_choice', '["Hoàn toàn lộn xộn, không có quy luật.","Theo thứ tự thời gian của các sự kiện lịch sử.","Các câu hỏi luôn xuất hiện theo đúng trình tự thông tin của văn bản từ trên xuống dưới.","Tất cả câu trả lời đều nằm ở đoạn cuối cùng."]', 'Các câu hỏi luôn xuất hiện theo đúng trình tự thông tin của văn bản từ trên xuống dưới.', 'Đây là đặc điểm quan trọng (In order) của dạng bài TFNG, giúp bạn định vị vùng chứa thông tin. Nếu bạn tìm thấy đáp án câu 1 và câu 3, thì câu 2 chắc chắn nằm ở đoạn giữa.'),
('ad8d7fe1-7a0e-42b4-be83-55728ca2829b', 'Sự khác biệt cốt lõi giữa dạng bài ''True/False/Not Given'' (TFNG) và ''Yes/No/Not Given'' (YNNG) là gì?', 'multiple_choice', '["TFNG dành cho phần thi Listening, YNNG dành cho Reading.","TFNG kiểm tra Sự thật khách quan (Factual information), trong khi YNNG kiểm tra Quan điểm và Tuyên bố của tác giả (Writer''s views/claims).","YNNG có nhiều từ vựng khó hơn TFNG.","Không có bất kỳ sự khác biệt nào."]', 'TFNG kiểm tra Sự thật khách quan (Factual information), trong khi YNNG kiểm tra Quan điểm và Tuyên bố của tác giả (Writer''s views/claims).', 'TFNG thường xuất hiện ở Passage 1 (văn bản cung cấp thông tin), trong khi YNNG xuất hiện ở Passage 2 hoặc 3 (văn bản nghị luận) đòi hỏi khả năng phân tích ý kiến của tác giả.'),
('ad8d7fe1-7a0e-42b4-be83-55728ca2829b', 'Trong dạng Yes/No/Not Given, nếu bài viết nói ''Nhiều chuyên gia cho rằng...'', nhưng câu hỏi nói ''Tác giả cho rằng...'', bạn nên chọn đáp án nào?', 'multiple_choice', '["Yes","No","Not Given","Tùy thuộc vào ngữ cảnh"]', 'Not Given', 'Ý kiến của ''nhiều chuyên gia'' không đại diện cho quan điểm của ''tác giả''. Nếu tác giả không trực tiếp đưa ra quan điểm cá nhân về vấn đề đó, đáp án là Not Given.'),
('ad8d7fe1-7a0e-42b4-be83-55728ca2829b', 'Khi đối mặt với các từ mang tính tuyệt đối (Absolute words) như ''all'', ''only'', ''always'', ''impossible'' trong câu hỏi YNNG, bạn nên làm gì?', 'multiple_choice', '["Luôn chọn đáp án ''No''.","Luôn chọn đáp án ''Not Given''.","Hết sức cẩn thận đối chiếu với văn bản, vì tác giả thường dùng các từ giảm nhẹ (Hedging) như ''some'', ''often'', ''difficult'', khiến câu nhận định trở thành ''No''.","Bỏ qua các từ đó vì chúng không quan trọng."]', 'Hết sức cẩn thận đối chiếu với văn bản, vì tác giả thường dùng các từ giảm nhẹ (Hedging) như ''some'', ''often'', ''difficult'', khiến câu nhận định trở thành ''No''.', 'Câu hỏi chứa từ tuyệt đối rất dễ bị sai (No) vì trong văn học thuật, các tác giả hiếm khi đưa ra các tuyên bố cực đoan 100%.'),
('c8d37c14-8582-4318-a566-dfaf68dc0500', 'Trong dạng bài Matching Headings, ''Heading'' (Tiêu đề) thường đóng vai trò gì đối với một đoạn văn?', 'multiple_choice', '["Một ví dụ minh họa chi tiết nhất.","Một số liệu thống kê quan trọng nhất.","Một cụm từ tóm tắt ý chính (Main idea) bao quát toàn bộ nội dung của đoạn văn đó.","Lời dẫn dắt sang đoạn văn tiếp theo."]', 'Một cụm từ tóm tắt ý chính (Main idea) bao quát toàn bộ nội dung của đoạn văn đó.', 'Heading không phải là một chi tiết (detail). Một heading đúng phải đủ rộng để bao trùm nội dung cả đoạn, nhưng đủ hẹp để không bị nhầm lẫn với đoạn khác.'),
('c8d37c14-8582-4318-a566-dfaf68dc0500', 'Chiến thuật nào sau đây là SAI lầm phổ biến nhất khi làm bài Matching Headings?', 'multiple_choice', '["Đọc lướt (Skim) để nắm cấu trúc tổng thể.","Tập trung đọc kỹ câu đầu và câu cuối của mỗi đoạn.","Chỉ tìm kiếm ''từ khóa'' (keywords) giống nhau giữa Heading và Đoạn văn rồi chọn ngay mà không đọc hiểu ý chính.","Gạch bỏ các Headings đã được chọn để làm hẹp danh sách."]', 'Chỉ tìm kiếm ''từ khóa'' (keywords) giống nhau giữa Heading và Đoạn văn rồi chọn ngay mà không đọc hiểu ý chính.', 'IELTS luôn sử dụng ''bẫy từ vựng'' (distractors). Một đoạn văn chứa chính xác từ khóa trong Heading thường KHÔNG phải là đáp án đúng, vì ý chính đã bị paraphrase bằng các từ đồng nghĩa.'),
('c8d37c14-8582-4318-a566-dfaf68dc0500', 'Nếu một đoạn văn bắt đầu bằng việc kể một câu chuyện dài hoặc nêu một ví dụ cụ thể, bạn nên làm gì để tìm Heading?', 'multiple_choice', '["Chọn Heading có chứa tên nhân vật trong câu chuyện.","Đọc lướt qua câu chuyện để tìm câu chốt ý (thường nằm ở cuối đoạn hoặc sau các từ nối như ''Therefore'', ''This illustrates'').","Đọc lại đoạn văn trước đó.","Bỏ qua đoạn văn đó không làm nữa."]', 'Đọc lướt qua câu chuyện để tìm câu chốt ý (thường nằm ở cuối đoạn hoặc sau các từ nối như ''Therefore'', ''This illustrates'').', 'Không phải đoạn văn nào cũng có Topic Sentence nằm ở đầu. Khi tác giả dùng ví dụ để mở đầu (Inductive reasoning), ý chính sẽ được đúc kết ở phần sau.'),
('f3fbefe7-eb21-435d-842e-9fe2ea9e9c7c', 'Trong dạng bài ''Matching Features'' (ví dụ: Ghép tên nhà khoa học với phát minh của họ), kỹ năng đọc nào là quan trọng nhất?', 'multiple_choice', '["Đọc hiểu chi tiết từng chữ (Close reading).","Đọc lướt lấy ý chính (Skimming).","Quét thông tin (Scanning) để tìm kiếm chính xác các Tên riêng, Ngày tháng, hoặc Chữ in hoa trong bài.","Đọc ngược từ dưới lên trên."]', 'Quét thông tin (Scanning) để tìm kiếm chính xác các Tên riêng, Ngày tháng, hoặc Chữ in hoa trong bài.', 'Tên người hoặc địa danh không thể bị paraphrase (viết lại), do đó Scanning là công cụ sắc bén nhất để định vị nhanh chóng đoạn văn chứa thông tin cần tìm.'),
('f3fbefe7-eb21-435d-842e-9fe2ea9e9c7c', 'Dòng hướng dẫn ''NB: You may use any letter more than once'' trong bài Matching Information có ý nghĩa gì?', 'multiple_choice', '["Bạn không được phép dùng một chữ cái hai lần.","Bạn có thể sử dụng một đáp án (chữ cái) cho nhiều hơn một câu hỏi.","Có một số chữ cái bạn không được dùng đến.","Bạn phải viết toàn bộ từ thay vì viết chữ cái."]', 'Bạn có thể sử dụng một đáp án (chữ cái) cho nhiều hơn một câu hỏi.', '''Nota Bene'' (NB) là lưu ý cực kỳ quan trọng. Khi dòng này xuất hiện, chắc chắn sẽ có ít nhất một đoạn văn (hoặc một tên người) chứa đáp án cho 2 câu hỏi khác nhau.'),
('f3fbefe7-eb21-435d-842e-9fe2ea9e9c7c', 'Dạng bài ''Matching Information to Paragraphs'' khác với ''Matching Headings'' ở điểm nào?', 'multiple_choice', '["Không có sự khác biệt.","Matching Information đi tìm ''Ý chính của đoạn'', còn Headings đi tìm ''Chi tiết''.","Matching Information yêu cầu tìm vị trí của một ''Thông tin chi tiết'' cụ thể nằm ở đâu, trong khi Headings yêu cầu tìm ''Ý chính bao quát'' của cả đoạn.","Matching Information luôn theo thứ tự văn bản."]', 'Matching Information yêu cầu tìm vị trí của một ''Thông tin chi tiết'' cụ thể nằm ở đâu, trong khi Headings yêu cầu tìm ''Ý chính bao quát'' của cả đoạn.', 'Tìm Information khó hơn tìm Headings vì thông tin cần tìm có thể chỉ là một câu ví dụ nhỏ nằm lọt thỏm ở giữa một đoạn văn dài.'),
('ee10d180-ee97-486b-917b-e8d5e114e975', 'Trong bài Multiple Choice (Trắc nghiệm), các lựa chọn (options) thường được thiết kế như thế nào để gài bẫy thí sinh?', 'multiple_choice', '["Các lựa chọn sai thường không có từ vựng nào giống trong bài.","Các lựa chọn sai thường chứa chính xác các từ vựng xuất hiện trong bài đọc, nhưng ghép chúng lại thành một câu có ý nghĩa sai hoặc không liên quan.","Các lựa chọn đúng luôn là câu dài nhất.","Các lựa chọn sai thường sai chính tả."]', 'Các lựa chọn sai thường chứa chính xác các từ vựng xuất hiện trong bài đọc, nhưng ghép chúng lại thành một câu có ý nghĩa sai hoặc không liên quan.', 'Đây là bẫy ''Word Matching'' (Nối từ). IELTS kiểm tra khả năng đọc hiểu ý nghĩa thực sự, chứ không phải bài thi tìm từ giống nhau.'),
('ee10d180-ee97-486b-917b-e8d5e114e975', 'Đối với dạng bài Short Answer Questions, nếu giới hạn là ''NO MORE THAN TWO WORDS'', bạn sẽ viết đáp án thế nào nếu đoạn văn ghi là ''the large modern library''?', 'multiple_choice', '["large modern library","modern library","the library","the large modern library"]', 'modern library', 'Bạn phải tuân thủ nghiêm ngặt giới hạn số từ. Việc bỏ đi mạo từ ''the'' hoặc tính từ ít quan trọng hơn (''large'') là cần thiết để giữ lại danh từ chính và tính từ bổ nghĩa sát nhất.'),
('ee10d180-ee97-486b-917b-e8d5e114e975', 'Thứ tự xuất hiện của các câu hỏi Multiple Choice trong IELTS Reading thường như thế nào?', 'multiple_choice', '["Ngẫu nhiên","Theo trật tự thông tin trong văn bản từ trên xuống dưới.","Từ khó đến dễ.","Chỉ tập trung vào đoạn kết luận."]', 'Theo trật tự thông tin trong văn bản từ trên xuống dưới.', 'Câu hỏi trắc nghiệm (MCQs) luôn đi theo dòng chảy của văn bản (In order), giúp bạn dễ dàng khoanh vùng thông tin để đọc kỹ.'),
('4bc7ed22-6653-4010-9d7c-7baae7516cbf', 'Khi làm dạng bài Summary Completion (Điền từ vào đoạn tóm tắt), kỹ năng nào sau đây đóng vai trò như một ''chiếc la bàn'' định hướng?', 'multiple_choice', '["Kỹ năng đoán nghĩa từ lóng.","Kiến thức Ngữ pháp (Grammar): Phân tích xem chỗ trống cần điền là Danh từ, Động từ, hay Tính từ để dự đoán và loại trừ từ sai.","Kỹ năng tính toán.","Kỹ năng đếm số chữ cái."]', 'Kiến thức Ngữ pháp (Grammar): Phân tích xem chỗ trống cần điền là Danh từ, Động từ, hay Tính từ để dự đoán và loại trừ từ sai.', 'Việc xác định loại từ (Parts of speech) kết hợp với ngữ cảnh giúp bạn loại bỏ 50% các đáp án không phù hợp dù chưa cần đọc kỹ văn bản.'),
('4bc7ed22-6653-4010-9d7c-7baae7516cbf', 'Trong dạng Summary Completion có cung cấp sẵn một hộp từ vựng (Box of words), đáp án sẽ như thế nào?', 'multiple_choice', '["Chắc chắn là những từ được trích xuất y nguyên (copy-paste) từ văn bản gốc.","Thường là các từ đồng nghĩa (Synonyms) hoặc từ cùng gốc (Word families) đã được paraphrase so với văn bản gốc.","Là các từ viết tắt.","Là những từ không liên quan đến bài."]', 'Thường là các từ đồng nghĩa (Synonyms) hoặc từ cùng gốc (Word families) đã được paraphrase so với văn bản gốc.', 'Khi có Box, IELTS đánh giá khả năng nhận diện Paraphrase của bạn. Bạn không thể tìm thấy chính xác từ đó trong bài đọc mà phải tìm ý nghĩa tương đương.'),
('4bc7ed22-6653-4010-9d7c-7baae7516cbf', 'Lỗi phổ biến nhất khi điền từ vào chỗ trống (Sentence Completion) lấy từ văn bản gốc là gì?', 'multiple_choice', '["Viết hoa sai.","Không thay đổi hình thái từ (ví dụ danh từ số ít/số nhiều) để phù hợp với ngữ pháp của câu hỏi.","Viết từ đồng nghĩa thay vì chép chính xác từ trong văn bản.","Chỉ viết một từ."]', 'Viết từ đồng nghĩa thay vì chép chính xác từ trong văn bản.', 'Nếu đề bài yêu cầu ''Choose words FROM THE TEXT'', bạn BẮT BUỘC phải chép y nguyên hình thái từ đó trong bài đọc, tuyệt đối không được tự ý paraphrase hay chia lại thì động từ.');